#include <iostream>
#include <algorithm>
using namespace std;
struct student
{
    string name;
    int chinese,math,english,sum,order;
};
bool func(student x,student y)
{
    if(x.sum!=y.sum)
    {
        return x.sum>y.sum;
    }
    else
    {
        return x.order<y.order;
    }
}
student a[1005];
int main()
{
    int n;
    cin>>n;
    for(int i=0;i<=n-1;i++)
    {
        cin>>a[i].name>>a[i].chinese>>a[i].math>>a[i].english;
        a[i].sum=a[i].chinese+a[i].math+a[i].english;
        a[i].order=i;
    }
    sort(a,a+n,func);
    cout<<a[0].name<<" "<<a[0].chinese<<" "<<a[0].math<<" "<<a[0].english;
    return 0;
}
